              <div className="flex flex-wrap gap-1 justify-center">
                {VARIABLE_GROUPS[1].vars.map((v) => (
                  <button
                    key={v}
                    onClick={() => handleButtonClick(v)}
                    className={PHYS_VAR_BTN}
                    title={`Insert ${v}`}
                  >
                    {v}
                  </button>
                ))}
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

import { useState } from 'react';
import { CheckCircle, XCircle, Lightbulb, ArrowRight, GraduationCap } from 'lucide-react';
import LabHeader from './LabHeader';
import MathFormula from './MathFormula';
import DerivationQuiz from './DerivationQuiz';
import { useTranslate } from '../i18n';

export interface DerivationStep {
  label: string;
  formula: string;
  detail: string;
}

export interface SliderConfig {
  label: string;
  key: string;
  min: number;
  max: number;
  step: number;
  default: number;
  unit: string;
}

export interface PracticeConfig {
  question: string;
  hint: string;
  answer: number;
  tolerance: number;
  explanation: string;
  errorHint: string;
}

export interface DerivationConfig {
  title: string;
  titleKey?: string;
  icon: React.ReactNode;
  accentGradient: string;
  accentColor: string;
  finalFormula: string;
  finalFormulaDesc: string;
  finalFormulaDescKey?: string;
  steps: DerivationStep[];
  sliders: SliderConfig[];
  compute: (values: Record<string, number>) => { traces: { label: string; value: string }[]; result: string };
  practice: PracticeConfig;
  keyInsight?: string;
  keyInsightKey?: string;
}

export function GenericDerivationLab({ onExit, config }: { onExit?: () => void; config: DerivationConfig }) {
  const [activeMobileTab, setActiveMobileTab] = useState<'theory' | 'test'>('theory');
  const { t } = useTranslate();
  const initialVals: Record<string, number> = {};
  config.sliders.forEach(s => { initialVals[s.key] = s.default; });
  const [vals, setVals] = useState<Record<string, number>>(initialVals);
  const [userAns, setUserAns] = useState('');
  const [checkResult, setCheckResult] = useState<'idle'|'correct'|'incorrect'>('idle');
  const computed = config.compute(vals);

  const checkAnswer = () => {
    const val = parseFloat(userAns);
    if (isNaN(val)) return;
    setCheckResult(Math.abs(val - config.practice.answer) < config.practice.tolerance ? 'correct' : 'incorrect');
  };

  return (
    <div className="flex flex-col min-h-screen lg:h-screen bg-slate-50 dark:bg-[#000000] font-sans select-none text-slate-800 dark:text-white overflow-x-hidden w-full">
      <LabHeader onExit={onExit} title={config.title} titleKey={config.titleKey} />
      
      {/* Mobile tab buttons */}
      <div className="w-full px-4 py-4 md:px-6 grid grid-cols-2 gap-2 shrink-0">
        <button onClick={() => setActiveMobileTab('theory')} className={`py-3 text-sm font-bold rounded-xl transition-all text-center ${activeMobileTab === 'theory' ? `${config.accentColor} text-white shadow-md` : 'bg-white dark:bg-[#1c1b1b] text-slate-600 dark:text-gray-400 border border-slate-200 dark:border-gray-700'}`}>{t('lab.tab.learn')}</button>
        <button onClick={() => setActiveMobileTab('test')} className={`py-3 text-sm font-bold rounded-xl transition-all text-center ${activeMobileTab === 'test' ? `${config.accentColor} text-white shadow-md` : 'bg-white dark:bg-[#1c1b1b] text-slate-600 dark:text-gray-400 border border-slate-200 dark:border-gray-700'}`}>{t('lab.tab.test')}</button>
      </div>
      
      <div className="lg:flex-1 flex flex-col lg:grid lg:grid-cols-5 gap-0 lg:gap-6 p-4 lg:p-6 lg:overflow-visible">
        {/* Left Column: Learn (Derivation steps) / Reference (Quiz) */}
        <div className={`lg:col-span-3 w-full bg-white dark:bg-[#121212] rounded-xl shadow-sm border border-slate-200 dark:border-[#1c1b1b] p-5 flex-col gap-4 lg:overflow-y-auto ${activeMobileTab === 'theory' ? 'flex lg:flex' : 'hidden lg:flex'}`}>
          {activeMobileTab === 'theory' ? (
            <>
              <div className="flex items-center gap-2 mb-3">
                <div className={`w-10 h-10 rounded-xl bg-gradient-to-br ${config.accentGradient} flex items-center justify-center shadow-lg`}>{config.icon}</div>
                <div><h2 className="text-lg font-bold">{t('lab.derivation_step_by_step')}</h2><p className="text-xs text-slate-500">{t('lab.derivation_step_desc')}</p></div>
              </div>
