                  </div>
                </div>
              </div>

              {/* All Steps Overview */}
              <div>
                <p className="text-xs font-bold uppercase tracking-wider text-slate-400 dark:text-slate-500 mb-2">
                  {t('lab.all_steps') || 'All Steps'}
                </p>
                <div className="space-y-1.5">
                  {config.steps.map((step, idx) => (
                    <div key={idx} className="flex items-center gap-2 p-2 rounded-lg bg-slate-50 dark:bg-[#1c1b1b] text-xs">
                      <div className={`w-5 h-5 rounded-full bg-gradient-to-br ${config.accentGradient} text-white flex items-center justify-center text-[9px] font-bold shrink-0 opacity-60`}>
                        {idx + 1}
                      </div>
                      <span className="text-slate-600 dark:text-slate-400 truncate flex-1">{step.label}</span>
                      <span className="text-yellow-500 font-mono text-[10px] truncate max-w-[100px] opacity-70">{step.formula}</span>
                    </div>
                  ))}
                </div>
              </div>
            </>
          )}
        </div>

        {/* Right Column: Test (Quiz) or Learn side panel */}
        <div className={`lg:col-span-3 lg:col-start-1 w-full bg-white dark:bg-[#121212] rounded-xl shadow-sm border border-slate-200 dark:border-[#1c1b1b] p-5 flex-col gap-4 lg:hidden ${activeMobileTab === 'test' ? 'flex' : 'hidden'}`}>
          <div className="flex items-center gap-2 mb-3">
            <div className={`w-10 h-10 rounded-xl bg-gradient-to-br ${config.accentGradient} flex items-center justify-center shadow-lg`}>
              <GraduationCap className="w-5 h-5 text-white" />
            </div>
            <div>
              <h2 className="text-lg font-bold">{t('lab.tab.test')}</h2>
              <p className="text-xs text-slate-500">{t('lab.quiz_enter_formula')}</p>
            </div>
          </div>
          <DerivationQuiz
            steps={config.steps}
            accentGradient={config.accentGradient}
            accentColor={config.accentColor}
            icon={config.icon}
            title={config.title}
            finalFormula={config.finalFormula}
            finalFormulaDesc={config.finalFormulaDesc}
          />
        </div>

        {/* Desktop right column - Test tab */}
        <div className={`hidden lg:flex ${activeMobileTab === 'test' ? 'lg:col-span-5' : 'lg:col-span-2'} w-full flex-col gap-5 ${activeMobileTab === 'test' ? 'flex' : ''}`}>
          <div className="bg-white dark:bg-[#121212] rounded-xl shadow-sm border border-slate-200 dark:border-[#2a2a2a] lg:dark:border-[#1c1b1b] p-5">
            <div className="flex items-center gap-2 mb-3">
              <GraduationCap className="w-5 h-5 opacity-60" />
              <h2 className="text-lg font-bold">{t('lab.tab.test')}</h2>
            </div>
            <p className="text-sm text-slate-500 mb-4">{t('lab.quiz_enter_formula')}</p>
            <DerivationQuiz
              steps={config.steps}
              accentGradient={config.accentGradient}
              accentColor={config.accentColor}
              icon={config.icon}
              title={config.title}
              finalFormula={config.finalFormula}
              finalFormulaDesc={config.finalFormulaDesc}
            />
          </div>
        </div>

        {/* Desktop left column - Learn tab stays visible */}
        <div className={`hidden lg:col-span-3 w-full bg-white dark:bg-[#121212] rounded-xl shadow-sm border border-slate-200 dark:border-[#1c1b1b] p-5 flex-col gap-4 lg:overflow-y-auto ${activeMobileTab === 'theory' ? 'lg:flex' : ''}`}>
          <div className="flex items-center gap-2 mb-3">
            <div className={`w-10 h-10 rounded-xl bg-gradient-to-br ${config.accentGradient} flex items-center justify-center shadow-lg`}>{config.icon}</div>
            <div><h2 className="text-lg font-bold">{t('lab.derivation_step_by_step')}</h2><p className="text-xs text-slate-500">{t('lab.derivation_step_desc')}</p></div>
          </div>
          <div className={`bg-gradient-to-br ${config.accentGradient} rounded-xl p-5 text-center shadow-lg mb-3`}>
            <p className={`text-xs text-white/70 font-semibold uppercase tracking-wider`}>{t('lab.final_formula')}</p>
            <div className="text-2xl font-bold text-white mt-1"><MathFormula formula={config.finalFormula} className="text-2xl font-bold" /></div>
            <p className="text-xs text-white/70 mt-1">{config.finalFormulaDescKey ? t(config.finalFormulaDescKey) : config.finalFormulaDesc}</p>
          </div>
          <div className="space-y-0">
            {config.steps.map((step, idx) => (
              <div key={idx} className="relative">
                <div className="flex gap-3">
                  <div className="flex flex-col items-center">
                    <div className={`w-8 h-8 rounded-full bg-gradient-to-br ${config.accentGradient} text-white flex items-center justify-center text-xs font-bold shadow-md shrink-0`}>{idx + 1}</div>
                    {idx < config.steps.length - 1 && <div className="w-0.5 h-full min-h-[24px] bg-gradient-to-b from-current to-current opacity-20" />}
                  </div>
                  <div className="flex-1 pb-4">
                    <div className={`bg-blue-50 dark:bg-blue-900/20 rounded-lg p-3 border border-blue-200 dark:border-blue-800 mb-1`}><p className="font-bold text-sm text-blue-800 dark:text-blue-300">{step.label}</p></div>
                    <div className="bg-[#000000] rounded-lg mx-1 my-1.5 px-3 py-3 text-center border border-[#1c1b1b]"><MathFormula formula={step.formula} className="text-lg font-bold text-yellow-400" /></div>
                    <p className="text-base text-slate-600 dark:text-slate-400 leading-relaxed px-1">{step.detail}</p>
                    {idx < config.steps.length - 1 && <div className="flex justify-center mt-1"><ArrowRight className="w-4 h-4 opacity-40" /></div>}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Desktop right column - Learn side panel (key insight + practice) */}
        <div className={`hidden lg:flex lg:col-span-2 w-full flex-col gap-5 ${activeMobileTab === 'theory' ? 'flex' : ''}`}>
          {/* Key Insight */}
          <div className="bg-amber-50 dark:bg-amber-900/20 rounded-xl p-4 border border-amber-200 dark:border-amber-800">
            <div className="flex items-start gap-2">
              <Lightbulb className="w-5 h-5 text-amber-500 shrink-0 mt-0.5" />
              <div><p className="font-bold text-sm text-amber-700 dark:text-amber-300">{t('lab.real_life_application')}</p><p className="text-sm text-amber-700 dark:text-amber-300 mt-1">{config.keyInsightKey ? t(config.keyInsightKey) : (config.keyInsight || t('lab.derivation_default_insight'))}</p></div>
            </div>
          </div>

          {/* Practice question (simplified) */}
          <div className="bg-white dark:bg-[#121212] rounded-xl shadow-sm border border-slate-200 dark:border-[#2a2a2a] lg:dark:border-[#1c1b1b] p-5">
            <h2 className="text-lg font-bold mb-3 flex items-center gap-2">{t('lab.practice_apply_derivation')}</h2>
            <div className="bg-slate-50 dark:bg-[#1c1b1b] rounded-lg p-4 border border-slate-200 dark:border-[#2a2a2a] mb-3">
              <p className="text-sm font-medium mb-2">{config.practice.question}</p>
              <div className={`bg-blue-50 dark:bg-blue-900/20 rounded p-2 mt-2`}><p className="text-xs text-blue-700 dark:text-blue-300 font-mono">{config.practice.hint}</p></div>
            </div>
            <div className="flex gap-2 mb-2">
              <input type="number" value={userAns} onChange={e => setUserAns(e.target.value)} placeholder={t('lab.practice_placeholder')} className="flex-1 px-3 py-2 text-sm border border-slate-300 dark:border-[#2a2a2a] rounded-lg bg-white dark:bg-[#121212] focus:ring-2 focus:ring-blue-500 outline-none" />
              <button onClick={checkAnswer} className={`px-4 py-2 bg-gradient-to-br ${config.accentGradient} hover:opacity-90 text-white text-sm font-semibold rounded-lg transition-all`}>{t('lab.check')}</button>
            </div>
            {checkResult === 'correct' && <div className="bg-emerald-50 dark:bg-emerald-900/20 rounded-lg p-3 border border-emerald-200 dark:border-emerald-800 flex items-center gap-2"><CheckCircle className="w-5 h-5 text-emerald-500 shrink-0" /><p className="text-xs text-emerald-700 dark:text-emerald-300"><strong>{t('lab.correct')}</strong> {config.practice.explanation}</p></div>}
            {checkResult === 'incorrect' && <div className="bg-red-50 dark:bg-red-900/20 rounded-lg p-3 border border-red-200 dark:border-red-800 flex items-center gap-2"><XCircle className="w-5 h-5 text-red-500 shrink-0" /><p className="text-xs text-red-700 dark:text-red-300"><strong>{t('lab.not_quite')}</strong> {config.practice.errorHint}</p></div>}
          </div>
        </div>
      </div>
    </div>
  );
}

export default GenericDerivationLab;

